  ////step 2 nation id check
  async nationIdCheck() {
    this.isNationIdCheckForm = true;
    let nation_id = this.nationIdCheckForm.controls.nationID.value.toString();
    let org_code = this.org_code_user_info;

    this.http
      .post<nationIdCheckObjects>(
        this.env.API_URL + `api/ClientRegistration/CheckNationalID`,
        {
          nation_id,
          org_code,
        }
      )
      .subscribe({
        next: (data) => {
          this.nationIdCheckVar = data;
          console.log("client data:", this.nationIdCheckVar);

          this.idImage = this.nationIdCheckVar.idImage;

          if (this.nationIdCheckVar.unregisteredClient == "1") {
            this.ClientCanBackIDinfoFlag = true;
            this.ClientCanBackBusInfoFlag = true;
            this.ClientCanBackUserPassFlag = true;
            this.ClientCanBackDocFlag = true;
            this.ClientCanBackEmailFlag = true;
          } else if (
            this.nationIdCheckVar.step_no != null &&
            this.nationIdCheckVar.existingClient == null
          ) {
            if (this.nationIdCheckVar.step_no == "3") {
              this.ClientCanBackIDinfoFlag = false;
              this.ClientCanBackBusInfoFlag = true;
            } else if (this.nationIdCheckVar.step_no == "4") {
              this.ClientCanBackUserPassFlag = true;
              //this.ClientCanBackBusInfoFlag = true;
              console.log(
                "ClientCanBackBusInfoFlag",
                this.ClientCanBackBusInfoFlag
              );
            } else if (this.nationIdCheckVar.step_no == "5") {
              this.ClientCanBackUserPassFlag = false;
              this.ClientCanBackDocFlag = true;
            }
          } else if (
            this.nationIdCheckVar.step_no != null &&
            this.nationIdCheckVar.existingClient == "1"
          ) {
            if (this.nationIdCheckVar.step_no == "2") {
              this.ClientCanBackBusInfoFlag = false;
            } else if (this.nationIdCheckVar.step_no == "4") {
              this.ClientCanBackUserPassFlag = false;
            }
          }

          if (this.nationIdCheckForm.controls.nationID.value.length < 1) {
            this.ErrorToastWithLogin("الرقم القومي لا يمكن ان يكون خالي"),
              (this.step1nextButtHide = true);
          } else if (
            this.nationIdCheckForm.controls.nationID.value.length == 14 &&
            this.nationIdCheckForm.controls.nationID.valid
          ) {
            this.nextButtAnimation();
            this.GetGenderFromNation();
            this.GetBirthYear1FromNation();
            this.GetBirthYear2FromNation();
            this.GetBirthMonthFromNation();
            this.GetBirthDayFromNation();
            this.fullBirtDate();
            this.nationIDbdateValidator();
          }
          if (
            (this.idRes.frontImage &&
              this.idRes.backImage &&
              this.idRes.faceImage != null) ||
            (this.idRes.frontImage &&
              this.idRes.backImage &&
              this.idRes.faceImage != "")
          ) {
            this.uploadOCRimgToTemp(this.idRes);
            this.OCRused = true;
          }

          this.getDocumentTypes();
        },
        error: (err) => {
          this.ErrorToast(err.error);
          console.log(err.error);
        },
      });
  }

