  async DetectIDImages() {
    let org_code = this.org_code_user_info;
    if (Capacitor.getPlatform() != "web") {
      if (this.imageSrcFront != undefined && this.imageSrcBack != undefined) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + `api/IDRecognition/ReadImages`, {
            image1: this.imageSrcFront.replace("data:image/jpeg;base64,", ""),
            image2: this.imageSrcBack.replace("data:image/jpeg;base64,", ""),
          })
          .subscribe({
            next: async (data) => {
              var successful = data["successful"];
              this.idRes = data["result"];
              if (this.idRes.faceImage != null)
                this.imageSrcFace =
                  "data:image/jpeg;base64," + this.idRes.faceImage;
              else {
                this.imageSrcFace = null;
              }
              if (this.idRes.frontImage != null)
                this.imageIdFront =
                  "data:image/jpeg;base64," + this.idRes.frontImage;
              else {
                this.imageIdFront = null;
              }
              if (this.idRes.backImage != null)
                this.imageIdBack =
                  "data:image/jpeg;base64," + this.idRes.backImage;
              else {
                this.imageIdBack = null;
              }
              this.ocrPatchValue(this.idRes);
              this.showLoader = false;
              if (successful != 1)
                await this.alertSerivce.showAlertError(
                  "قد تكون النتيجة غير صحيحة",
                  false
                );
            },
            error: async (err) => {
              this.showLoader = false;
              await this.alertSerivce.showAlertError(err.error, false);
            },
          });
      } else {
        await this.alertSerivce.showAlertError(
          "Please take ID photos first",
          false
        );
      }
    } else {
      await this.alertSerivce.showAlertError(
        "Web is not supported for this function",
        false
      );
    }
  }

