  async nationIDbdateValidator() {
    let testedBDay = new String(this.nationIdCheckForm.controls.nationID.value)
      .slice(5, -7)
      .toString();
    let testedBMonth = new String(
      this.nationIdCheckForm.controls.nationID.value
    )
      .slice(3, -9)
      .toString();
    let testedBYear = new String(this.nationIdCheckForm.controls.nationID.value)
      .slice(1, -11)
      .toString();
    let fullYear = this.BirthYear1 + testedBYear;
    let yearMonth = fullYear + "-" + testedBMonth;
    const maxMonths = "12";
    let currentYear = new Date().getFullYear().toString();
    let date = new Date();
    let formatedCurrentDate = date.toISOString().split("T")[0];
    let currentDate = new Date(formatedCurrentDate);
    let fullTestedIDdate = new Date(
      this.BirthYear1 + testedBYear + "-" + testedBMonth + "-" + testedBDay
    );
    let DaysOfMonth = this.getMonthDaysCount(yearMonth).toString();

    console.log("fullTestedIDdate....", fullTestedIDdate);
    console.log("currentDate", formatedCurrentDate);
    console.log("currentYear is:", currentYear);
    console.log("fullYear is:", fullYear);

    if (
      testedBDay > DaysOfMonth ||
      testedBMonth > maxMonths ||
      fullYear > currentYear ||
      fullTestedIDdate > currentDate
    ) {
      await this.alertSerivce.showAlertError(
        "برجاء التحقق من كتابة الرقم القومي بشكل صحيح",
        false
      );
      this.validationPersonalInfoForm.valid == null;
      this.step1nextButtHide = true;
    } else {
      this.validationPersonalInfoForm.valid == true;
      this.step1nextButtHide = false;
    }
  }

